SELECT drought_level
FROM drought_monitoring
WHERE province_id = 1 AND year = 1 AND week = 1;

SELECT AVG(machine_learning_prediction) AS avg_prediction
FROM drought_monitoring
WHERE data_source = 'Ground Station';

SELECT AVG(machine_learning_prediction) AS average_prediction
FROM drought_monitoring
WHERE province_id = 0;

SELECT AVG(machine_learning_prediction) AS average_prediction
FROM drought_monitoring
WHERE province_id = 0 AND year = 0;

SELECT drought_level
FROM drought_monitoring
WHERE province_id = 1 AND year = (
  SELECT MAX(year)
  FROM drought_monitoring
);

SELECT province_id, AVG(machine_learning_prediction) as average_prediction
FROM drought_monitoring
GROUP BY province_id;

SELECT drought_level
FROM drought_monitoring
WHERE province_id = 0;

SELECT drought_level
FROM drought_monitoring
WHERE province_id = 0 AND year = 2022;

SELECT province_id, COUNT(*) as record_count
FROM drought_monitoring
GROUP BY province_id;
